import { createVNode, render, type Directive } from 'vue'
import { isClient } from '@/lib/env'
import Spinner from '@/components/ui/spinner/Spinner.vue'

interface LoadingEl extends HTMLElement {
    _loading?: {
        mask: HTMLDivElement
        originalPosition: string
        textSpan?: HTMLSpanElement
    }
}

/**
 * v-loading 指令：为宿主元素添加局部加载遮罩和 Spinner。
 * 具备 SSR 环境安全保护、动态定位劫持与还原、以及粗野主义风格文字。
 */
export const vLoading: Directive<LoadingEl, boolean> & { getSSRProps?: () => Record<string, unknown> } = {
    mounted(el, binding) {
        if (!isClient) return

        // 1. 获取挂载前的 position 样式
        const originalPosition = el.style.position || window.getComputedStyle(el).position

        // 2. 创建遮罩容器
        const mask = document.createElement('div')
        mask.className = 'absolute inset-0 flex flex-col items-center justify-center z-50 select-none bg-white/80 dark:bg-brutal-black/80 transition-opacity duration-150'
        mask.style.display = binding.value ? 'flex' : 'none'

        // 3. 实例化 Spinner 并挂载
        const spinnerContainer = document.createElement('div')
        const spinnerVnode = createVNode(Spinner, { size: 'lg' })
        render(spinnerVnode, spinnerContainer)

        const spinnerEl = spinnerContainer.firstElementChild
        if (spinnerEl) {
            mask.appendChild(spinnerEl)
        }

        // 4. 解析加载文本，支持 element-loading-text 或者是 loading-text 属性
        const text = el.getAttribute('element-loading-text') || el.getAttribute('loading-text')
        let textSpan: HTMLSpanElement | undefined
        if (text) {
            textSpan = document.createElement('span')
            textSpan.className = 'mt-3 text-sm font-black text-brutal-black dark:text-white uppercase tracking-wider bg-brutal-yellow px-2 py-0.5 border border-brutal-black shadow-[2px_2px_0px_0px_rgba(0,0,0,1)]'
            textSpan.textContent = text
            mask.appendChild(textSpan)
        }

        // 5. 保存参数
        el._loading = {
            mask,
            originalPosition,
            textSpan
        }

        // 6. 挂载到宿主
        el.appendChild(mask)

        // 7. 处理定位
        if (binding.value) {
            togglePosition(el, true)
        }
    },

    updated(el, binding) {
        if (!isClient || !el._loading) return

        const { mask, textSpan } = el._loading

        // 切换可见性
        mask.style.display = binding.value ? 'flex' : 'none'

        // 动态更新文本
        const text = el.getAttribute('element-loading-text') || el.getAttribute('loading-text')
        if (text) {
            if (textSpan) {
                textSpan.textContent = text
            } else {
                const newSpan = document.createElement('span')
                newSpan.className = 'mt-3 text-sm font-black text-brutal-black dark:text-white uppercase tracking-wider bg-brutal-yellow px-2 py-0.5 border border-brutal-black shadow-[2px_2px_0px_0px_rgba(0,0,0,1)]'
                newSpan.textContent = text
                mask.appendChild(newSpan)
                el._loading.textSpan = newSpan
            }
        } else if (textSpan) {
            textSpan.remove()
            el._loading.textSpan = undefined
        }

        togglePosition(el, binding.value)
    },

    unmounted(el) {
        if (!isClient || !el._loading) return

        const { mask, originalPosition } = el._loading

        // 还原宿主 position
        if (originalPosition) {
            el.style.position = originalPosition
        } else {
            el.style.removeProperty('position')
        }

        // 卸载与清理
        mask.remove()
        delete el._loading
    },
    getSSRProps() {
        return {}
    }
}

function togglePosition(el: LoadingEl, loading: boolean) {
    if (!el._loading) return

    if (loading) {
        const currentPosition = window.getComputedStyle(el).position
        if (currentPosition === 'static' || currentPosition === '') {
            el.style.position = 'relative'
        }
    } else {
        const { originalPosition } = el._loading
        if (originalPosition === 'static' || originalPosition === '') {
            el.style.position = ''
        } else if (originalPosition) {
            el.style.position = originalPosition
        } else {
            el.style.removeProperty('position')
        }
    }
}

/**
 * Environment detection utilities for SSR compatibility.
 * Use these instead of scattered `typeof document/window` checks.
 */

/** Whether the code is running in a browser environment (not SSR). */
export const isClient = typeof window !== 'undefined'

/** Whether `document` is available. */
export const hasDocument = typeof document !== 'undefined'

/** Whether `localStorage` is available (may be blocked in Safari private mode). */
export const hasLocalStorage = typeof localStorage !== 'undefined'

/** Whether `document.body` is available for imperative mounting. */
export function canUseDocumentBody(): boolean {
    return hasDocument && document.body !== null
}

/** Whether IntersectionObserver is available. */
export const hasIntersectionObserver = isClient && typeof window.IntersectionObserver !== 'undefined'

type AudioContextConstructor = typeof AudioContext
type ResizeObserverConstructor = typeof ResizeObserver
type MutationObserverConstructor = typeof MutationObserver

export interface ViewportSize {
    width: number
    height: number
}

/** Get the available AudioContext constructor, including Safari's prefixed API. */
export function getAudioContextCtor(): AudioContextConstructor | null {
    if (!isClient) return null
    return window.AudioContext
        ?? (window as Window & typeof globalThis & { webkitAudioContext?: AudioContextConstructor }).webkitAudioContext
        ?? null
}

/** Get the available ResizeObserver constructor. */
export function getResizeObserverCtor(): ResizeObserverConstructor | null {
    if (!isClient) return null
    return window.ResizeObserver ?? null
}

/** Get the available MutationObserver constructor. */
export function getMutationObserverCtor(): MutationObserverConstructor | null {
    if (!isClient) return null
    return window.MutationObserver ?? null
}

/** Get the current device pixel ratio with an SSR-safe fallback. */
export function getDevicePixelRatio(): number {
    if (!isClient) return 1
    return window.devicePixelRatio || 1
}

/** Get viewport dimensions with an SSR-safe fallback. */
export function getViewportSize(): ViewportSize {
    if (!isClient) return { width: 0, height: 0 }
    return {
        width: window.innerWidth,
        height: window.innerHeight,
    }
}

/** Create a canvas element when the DOM supports it. */
export function createCanvasElement(): HTMLCanvasElement | null {
    if (!hasDocument) return null
    try {
        return document.createElement('canvas')
    } catch {
        return null
    }
}

/** Get a 2D rendering context without leaking capability errors to callers. */
export function getCanvas2DContext(canvas: HTMLCanvasElement): CanvasRenderingContext2D | null {
    try {
        return canvas.getContext('2d')
    } catch {
        return null
    }
}

/**
 * Safely get a value from localStorage.
 * Returns `null` if localStorage is unavailable or the key doesn't exist.
 */
export function safeGetStorageItem(key: string): string | null {
    try {
        if (!hasLocalStorage) return null
        return localStorage.getItem(key)
    } catch {
        return null
    }
}

/**
 * Safely set a value in localStorage.
 * Silently fails if localStorage is unavailable (e.g. Safari private mode, storage full).
 */
export function safeSetStorageItem(key: string, value: string): void {
    try {
        if (!hasLocalStorage) return
        localStorage.setItem(key, value)
    } catch {
        // Storage full or blocked (e.g. Safari private mode)
    }
}
